"use client";

import { useRef, useMemo, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';
import { gsap } from 'gsap';

// ─── WebGL Particle System ──────────────────────────────────────────────────
function ParticleSwarm() {
  const pointsRef = useRef<THREE.Points>(null);
  const { mouse } = useThree();

  const count = 3500;
  const particlesPosition = useMemo(() => {
    const positions = new Float32Array(count * 3);
    const colors = new Float32Array(count * 3);

    // Violet palette variants
    const palette = [
      new THREE.Color('#8B5CF6'), // violet-500
      new THREE.Color('#A78BFA'), // violet-400
      new THREE.Color('#C4B5FD'), // violet-300
      new THREE.Color('#DDD6FE'), // violet-200
      new THREE.Color('#6D28D9'), // violet-700
    ];

    for (let i = 0; i < count; i++) {
      const distance = Math.pow(Math.random(), 1 / 3) * 18;
      const theta = THREE.MathUtils.randFloatSpread(360);
      const phi = THREE.MathUtils.randFloatSpread(360);

      positions[i * 3]     = distance * Math.sin(theta) * Math.cos(phi);
      positions[i * 3 + 1] = distance * Math.sin(theta) * Math.sin(phi);
      positions[i * 3 + 2] = distance * Math.cos(theta);

      const color = palette[Math.floor(Math.random() * palette.length)];
      colors[i * 3]     = color.r;
      colors[i * 3 + 1] = color.g;
      colors[i * 3 + 2] = color.b;
    }
    return { positions, colors };
  }, [count]);

  useFrame((state) => {
    if (!pointsRef.current) return;
    const t = state.clock.getElapsedTime();

    // Base slow rotation
    pointsRef.current.rotation.y = t * 0.04;

    // Mouse-reactive tilt (layered on top via gsap)
    gsap.to(pointsRef.current.rotation, {
      x: (mouse.y * Math.PI) / 12,
      y: t * 0.04 + (mouse.x * Math.PI) / 12,
      duration: 2.5,
      ease: "power2.out",
      overwrite: "auto",
    });
  });

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={particlesPosition.positions.length / 3}
          array={particlesPosition.positions}
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-color"
          count={particlesPosition.colors.length / 3}
          array={particlesPosition.colors}
          itemSize={3}
        />
      </bufferGeometry>
      <pointsMaterial
        size={0.06}
        vertexColors
        transparent
        opacity={0.7}
        sizeAttenuation
        blending={THREE.AdditiveBlending}
        depthWrite={false}
      />
    </points>
  );
}

// ─── Hero Section ──────────────────────────────────────────────────────────
